import { useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [search, setSearch] = useState("");
  const [searched, setSearched] = useState(false);

  const [date, setDate] = useState("");
  const [time1, setTime1] = useState("");
  const [time2, setTime2] = useState("");
  const [time3, setTime3] = useState("");

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed to fetch workers");
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* TOP */}

        <div style={styles.top}>

          <div>

            <h1 style={styles.heading}>
              Find Workers
            </h1>

            <p style={styles.subtext}>
              Search skilled workers near you
            </p>

          </div>

        </div>

        {/* SEARCH BAR */}

        <div style={styles.searchCard}>

          <input
            style={styles.input}
            placeholder="Search worker type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <input
            type="date"
            style={styles.input}
            value={date}
            onChange={(e) =>
              setDate(e.target.value)
            }
          />

          <select
            style={styles.input}
            onChange={(e) =>
              setTime1(e.target.value)
            }
          >
            <option>
              Preferred Time 1
            </option>

            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime2(e.target.value)
            }
          >
            <option>
              Preferred Time 2
            </option>

            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime3(e.target.value)
            }
          >
            <option>
              Preferred Time 3
            </option>

            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* NO DATA */}

        {searched && workers.length === 0 && (

          <div style={styles.emptyBox}>
            No workers found
          </div>

        )}

        {/* WORKERS */}

        <div style={styles.grid}>

          {workers.map(worker => (

            <div
              key={worker._id}
              style={styles.card}
            >

              <div style={styles.profile}>

                <div style={styles.avatar}>
                  {worker.name?.charAt(0)}
                </div>

                <div>

                  <h2 style={styles.name}>
                    {worker.name}
                  </h2>

                  <p style={styles.skill}>
                    {worker.skills?.join(", ")}
                  </p>

                </div>

              </div>

              <div style={styles.infoBox}>

                <p style={styles.info}>
                  📍 {worker.city}, {worker.area}
                </p>

                <p style={styles.info}>
                  📞 {worker.phone}
                </p>

                <p style={styles.info}>
                  ₹ {worker.price}
                </p>

              </div>

              <div style={styles.dateBox}>

                <p style={styles.workText}>
                  Work Date:
                </p>

                <span style={styles.badge}>
                  {date || "Not Selected"}
                </span>

              </div>

              <div style={styles.timeWrap}>

                {time1 && (
                  <span style={styles.timeBadge}>
                    {time1}
                  </span>
                )}

                {time2 && (
                  <span style={styles.timeBadge}>
                    {time2}
                  </span>
                )}

                {time3 && (
                  <span style={styles.timeBadge}>
                    {time3}
                  </span>
                )}

              </div>

              <button style={styles.requestBtn}>
  Send Request
</button>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 60px"
  },

  top: {
    marginBottom: "30px"
  },

  heading: {
    fontSize: "32px",
    marginBottom: "8px",
    color: "#111827"
  },

  subtext: {
    color: "#6b7280"
  },

  searchCard: {
    background: "white",
    padding: "25px",
    borderRadius: "16px",
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))",
    gap: "15px",
    marginBottom: "35px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.04)"
  },

  input: {
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    fontSize: "14px",
    outline: "none"
  },

  searchBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    padding: "14px",
    cursor: "pointer",
    fontWeight: "500"
  },

  emptyBox: {
    background: "white",
    padding: "30px",
    borderRadius: "14px",
    textAlign: "center",
    color: "#6b7280"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "22px"
  },

  card: {
    background: "white",
    borderRadius: "18px",
    padding: "24px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.05)"
  },

  profile: {
    display: "flex",
    alignItems: "center",
    gap: "15px",
    marginBottom: "20px"
  },

  avatar: {
    width: "52px",
    height: "52px",
    borderRadius: "50%",
    background: "#2563eb",
    color: "white",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "20px",
    fontWeight: "bold"
  },

  name: {
    margin: 0,
    fontSize: "20px",
    color: "#111827"
  },

  skill: {
    color: "#6b7280",
    marginTop: "5px",
    fontSize: "14px"
  },

  infoBox: {
    marginBottom: "18px"
  },

  info: {
    marginBottom: "10px",
    color: "#374151",
    fontSize: "14px"
  },

  dateBox: {
    marginBottom: "15px"
  },

  workText: {
    marginBottom: "8px",
    fontSize: "14px",
    color: "#374151"
  },

  badge: {
    background: "#eef2ff",
    color: "#2563eb",
    padding: "7px 12px",
    borderRadius: "8px",
    fontSize: "13px"
  },

  timeWrap: {
    display: "flex",
    flexWrap: "wrap",
    gap: "10px",
    marginBottom: "22px"
  },

  timeBadge: {
    background: "#f3f4f6",
    padding: "8px 12px",
    borderRadius: "8px",
    fontSize: "13px",
    color: "#374151"
  },

  requestBtn: {
    width: "100%",
    background: "#2563eb",
